{"code": "import json

# Load the full language data
languages_file = locals()['var_functions.query_db:20']
with open(languages_file, 'r') as f:
    all_repos = json.load(f)

# Create a dictionary mapping repo_name to whether it uses Python
repo_uses_python = {}
total_repos = 0

for repo in all_repos:
    total_repos += 1
    repo_name = repo['repo_name']
    lang_desc = repo['language_description'].lower()
    # Check if Python is mentioned in the language description
    uses_python = 'python' in lang_desc
    repo_uses_python[repo_name] = uses_python

non_python_repos = {name for name, uses_py in repo_uses_python.items() if not uses_py}

print('__RESULT__:')
print(json.dumps({
    'total_repos': total_repos,
    'non_python_repos': len(non_python_repos),
    'python_repos': total_repos - len(non_python_repos),
    'sample_python_status': {k: repo_uses_python[k] for k in list(repo_uses_python.keys())[:10]}
}))"}
